const { execSync } = require('child_process');
const transcriptPath = $input.first().json.body.transcript_path;
const stdout = execSync('python /data/scripts/parse_transcript.py --file "' + transcriptPath + '"', { encoding: 'utf-8' });
return [{json: { stdout: stdout.trim() }}];

const output = JSON.parse($input.first().json.stdout);
return [{
  json: {
    account_id: output.account_id,
    company_name: output.company_name,
    memo_path: output.memo_path,
    spec_path: output.spec_path,
    status: output.status,
    pipeline: 'A',
    version: 'v1',
    timestamp: new Date().toISOString()
  }
}];
